 49‚Üí      const objMatch = code.match(/module\.exports\s*=\s*\{([^}]+)\}/);
 50‚Üí      if (objMatch) {
 51‚Üí        const isIdentifier = /^[a-zA-Z_$][a-zA-Z0-9_$]*$/;
 52‚Üí        const entries = objMatch[1]
 53‚Üí          .split(',')
 54‚Üí          .map(e => e.trim())
 55‚Üí          .filter(Boolean)
 56‚Üí          .filter(e => {
 57‚Üí            const parts = e.split(':').map(p => p.trim());
 58‚Üí            return parts.every(p => isIdentifier.test(p));
 59‚Üí          })
 60‚Üí          .map(e => {
 61‚Üí            const parts = e.split(':').map(p => p.trim());
 62‚Üí            if (parts.length === 2 && parts[0] !== parts[1]) {
 63‚Üí              return `export { ${parts[1]} as ${parts[0]} };`;
 64‚Üí            }
 65‚Üí            return `export { ${parts[0]} };`;
 66‚Üí          });
 67‚Üí        const exportsBlock = entries.join('\n');
 68‚Üí        return code
 69‚Üí          .replace(/["']use strict["'];?\s*/, '')
